import { useState, useEffect, useRef } from 'react';
import { SlideData, INITIAL_SLIDE, createNewSlide, SlideLayout, ThemeId, TypographyId, THEMES, TYPOGRAPHY_STYLES, ProjectMetadata } from '../types';
import { supabase } from '../services/supabaseClient';

export const usePresentation = () => {
    // Current Project State
    const [currentProjectId, setCurrentProjectId] = useState<string | number | null>(null);
    const [currentProjectName, setCurrentProjectName] = useState<string>("Untitled Project");
    const [slides, setSlides] = useState<SlideData[]>([INITIAL_SLIDE]);
    const [currentSlideIndex, setCurrentSlideIndex] = useState(0);

    // App State
    const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');
    const [isLoaded, setIsLoaded] = useState(false);
    const isFirstLoad = useRef(true);

    // Project List State
    const [savedProjects, setSavedProjects] = useState<ProjectMetadata[]>([]);
    const [isLoadingProjects, setIsLoadingProjects] = useState(false);

    const currentSlide = slides[currentSlideIndex] || slides[0];

    // --- Persistence Logic ---

    // Fetch Project List
    const fetchProjects = async () => {
        setIsLoadingProjects(true);
        try {
            // Select relevant fields. Order by updated_at descending
            const { data, error } = await supabase
                .from('presentations')
                .select('id, name, updated_at')
                .order('updated_at', { ascending: false });

            if (error) throw error;
            if (data) {
                setSavedProjects(data as ProjectMetadata[]);
            }
        } catch (e) {
            console.error("Failed to fetch projects list:", e);
        } finally {
            setIsLoadingProjects(false);
        }
    };

    // Initial Load of Project List
    useEffect(() => {
        fetchProjects();
        // Don't auto-load a specific project initially, wait for user selection
        // unless there is no project at all, but the Welcome Screen handles that.
        setIsLoaded(true);
        setTimeout(() => { isFirstLoad.current = false; }, 500);
    }, []);

    // Load Specific Project
    const loadRemoteProject = async (id: string | number) => {
        setIsLoaded(false);
        try {
            const { data, error } = await supabase
                .from('presentations')
                .select('*')
                .eq('id', id)
                .single();

            if (error) throw error;
            if (data) {
                setSlides(data.slides || [INITIAL_SLIDE]);
                setCurrentProjectId(data.id);
                setCurrentProjectName(data.name || "Untitled");
                setCurrentSlideIndex(0);
            }
        } catch (e) {
            console.error("Failed to load project:", e);
            alert("Could not load project.");
        } finally {
            setIsLoaded(true);
        }
    };

    // Create New Remote Project
    const createNewRemoteProject = async (name: string, initialSlides: SlideData[]) => {
        setIsLoaded(false);
        try {
            const { data, error } = await supabase
                .from('presentations')
                .insert([{
                    name: name,
                    slides: initialSlides,
                    updated_at: new Date().toISOString()
                }])
                .select()
                .single();

            if (error) throw error;
            if (data) {
                setCurrentProjectId(data.id);
                setCurrentProjectName(data.name);
                setSlides(initialSlides);
                setCurrentSlideIndex(0);
                fetchProjects(); // Refresh list
            }
        } catch (e) {
            console.error("Failed to create project:", e);
            // Fallback for offline or error: just set state
            setSlides(initialSlides);
            setCurrentProjectName(name);
            setCurrentProjectId(Date.now()); // Temp ID
            setCurrentSlideIndex(0);
        } finally {
            setIsLoaded(true);
        }
    };

    // Duplicate Project
    const duplicateProject = async (id: string | number) => {
        try {
            const { data: original, error: fetchError } = await supabase
                .from('presentations')
                .select('*')
                .eq('id', id)
                .single();

            if (fetchError) throw fetchError;
            if (!original) return;

            const newName = `Copy of ${original.name}`;
            const { error: insertError } = await supabase
                .from('presentations')
                .insert([{
                    name: newName,
                    slides: original.slides,
                    updated_at: new Date().toISOString()
                }]);

            if (insertError) throw insertError;
            fetchProjects();
        } catch (e) {
            console.error("Failed to duplicate:", e);
        }
    };

    // Save Helper
    const saveToCloud = async (slidesToSave: SlideData[]) => {
        if (!currentProjectId) return; // Can't save without an ID (should be created via createNewRemoteProject first usually)

        setSaveStatus('saving');
        try {
            const { error } = await supabase
                .from('presentations')
                .upsert({ 
                    id: currentProjectId, 
                    name: currentProjectName,
                    slides: slidesToSave,
                    updated_at: new Date().toISOString()
                });

            if (error) throw error;
            setSaveStatus('saved');
            setTimeout(() => setSaveStatus('idle'), 2000);
            fetchProjects(); // Refresh list to update timestamp
        } catch (error: any) {
            console.error("Failed to save to Supabase:", error);
            setSaveStatus('error');
        }
    };

    // Rename Project
    const renameProject = async (id: string | number, newName: string) => {
        try {
            const { error } = await supabase
                .from('presentations')
                .update({ name: newName })
                .eq('id', id);

            if (error) throw error;

            // Update local state if it's the active project
            if (id === currentProjectId) {
                setCurrentProjectName(newName);
            }
            fetchProjects();
        } catch (e) {
            console.error("Failed to rename:", e);
        }
    };

    // Delete Project
    const deleteProject = async (id: string | number) => {
        try {
            const { error } = await supabase
                .from('presentations')
                .delete()
                .eq('id', id);

            if (error) throw error;

            // If deleted current project, unload it? Or just let it stay in memory until switch
            if (id === currentProjectId) {
                setCurrentProjectId(null); // Optional: kick to welcome screen logic handled by UI
            }
            fetchProjects();
        } catch (e) {
            console.error("Failed to delete:", e);
        }
    };

    // Auto-Save
    useEffect(() => {
        if (!isLoaded || isFirstLoad.current || !currentProjectId) return;
        const timeoutId = setTimeout(() => {
            saveToCloud(slides);
        }, 2000);
        return () => clearTimeout(timeoutId);
    }, [slides, isLoaded, currentProjectId, currentProjectName]);


    // --- Slide Operations ---

    const handleUpdateSlide = (updatedSlide: SlideData) => {
        const oldSlide = slides[currentSlideIndex];
        let newSlides = slides.map((s, index) => index === currentSlideIndex ? updatedSlide : s);

        // Apply Global changes logic
        if (oldSlide.theme !== updatedSlide.theme) {
            newSlides = newSlides.map(s => ({ ...s, theme: updatedSlide.theme }));
        }
        if (oldSlide.typography !== updatedSlide.typography) {
            newSlides = newSlides.map(s => ({ ...s, typography: updatedSlide.typography }));
        }
        if (oldSlide.textTransition !== updatedSlide.textTransition) {
            newSlides = newSlides.map(s => ({ ...s, textTransition: updatedSlide.textTransition }));
        }
        if (oldSlide.imageTransition !== updatedSlide.imageTransition) {
            newSlides = newSlides.map(s => ({ ...s, imageTransition: updatedSlide.imageTransition }));
        }
        if (oldSlide.textOutroTransition !== updatedSlide.textOutroTransition) {
            newSlides = newSlides.map(s => ({ ...s, textOutroTransition: updatedSlide.textOutroTransition }));
        }
        if (oldSlide.imageOutroTransition !== updatedSlide.imageOutroTransition) {
            newSlides = newSlides.map(s => ({ ...s, imageOutroTransition: updatedSlide.imageOutroTransition }));
        }

        setSlides(newSlides);
    };

    const handleAddSlide = (layout: SlideLayout = 'text-image') => {
        const newSlide = createNewSlide(layout);
        const refSlide = slides[currentSlideIndex] || slides[0];
        // Inherit styles
        newSlide.theme = refSlide.theme || 'cyber-future';
        newSlide.typography = refSlide.typography || 'modern-sans';
        newSlide.textTransition = refSlide.textTransition || 'slide-up';
        newSlide.imageTransition = refSlide.imageTransition || 'zoom-in';
        newSlide.textOutroTransition = refSlide.textOutroTransition || 'none';
        newSlide.imageOutroTransition = refSlide.imageOutroTransition || 'none';

        const lastSlide = slides[slides.length - 1];
        if (lastSlide && lastSlide.badge.startsWith('Step ')) {
            const num = parseInt(lastSlide.badge.split(' ')[1]);
            if (!isNaN(num)) newSlide.badge = `Step ${num + 1}`;
        }

        setSlides([...slides, newSlide]);
        setCurrentSlideIndex(slides.length);
    };

    const handleDuplicateSlide = (index: number) => {
        const slide = slides[index];
        if (!slide) return;
        const newSlide = { ...slide, id: Date.now().toString() };
        const newSlides = [...slides];
        newSlides.splice(index + 1, 0, newSlide);
        setSlides(newSlides);
        setCurrentSlideIndex(index + 1);
    };

    const handleDeleteSlide = (index: number) => {
        if (slides.length <= 1) return;
        const newSlides = slides.filter((_, i) => i !== index);
        setSlides(newSlides);
        if (currentSlideIndex >= index && currentSlideIndex > 0) {
            setCurrentSlideIndex(currentSlideIndex - 1);
        } else if (currentSlideIndex >= newSlides.length) {
            setCurrentSlideIndex(newSlides.length - 1);
        }
    };

    const handleReorderSlides = (from: number, to: number) => {
        if (from === to) return;
        const newSlides = [...slides];
        const [moved] = newSlides.splice(from, 1);
        newSlides.splice(to, 0, moved);
        setSlides(newSlides);

        if (currentSlideIndex === from) setCurrentSlideIndex(to);
        else if (from < currentSlideIndex && to >= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex - 1);
        else if (from > currentSlideIndex && to <= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex + 1);
    };

    const applyTheme = (id: ThemeId) => setSlides(slides.map(s => ({ ...s, theme: id })));
    const applyTypography = (id: TypographyId) => setSlides(slides.map(s => ({ ...s, typography: id })));

    const randomizeLook = () => {
        const t = THEMES[Math.floor(Math.random() * THEMES.length)];
        const f = TYPOGRAPHY_STYLES[Math.floor(Math.random() * TYPOGRAPHY_STYLES.length)];
        setSlides(slides.map(s => ({ ...s, theme: t.id, typography: f.id })));
    };

    // --- New Project Management ---

    // Starts a brand new project, defaulting to current date name
    const startNewProject = () => {
        const dateStr = new Date().toLocaleString();
        const name = `Project - ${dateStr}`;
        const freshSlide = createNewSlide('text-image');

        createNewRemoteProject(name, [freshSlide]);
    };

    // Imports a JSON file as a new project
    const importProjectFile = (file: File) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const json = JSON.parse(e.target?.result as string);
                if (Array.isArray(json) && json.length > 0 && json[0].id) {
                    // Create as new project in DB
                    const dateStr = new Date().toLocaleString();
                    const name = `Imported - ${dateStr}`;
                    createNewRemoteProject(name, json as SlideData[]);
                } else {
                    alert("Invalid project file.");
                }
            } catch (err) {
                console.error(err);
                alert("Failed to parse project file.");
            }
        };
        reader.readAsText(file);
    };

    // Download current JSON
    const downloadProjectFile = () => {
        try {
            const blob = new Blob([JSON.stringify(slides, null, 2)], { type: "application/json" });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${currentProjectName.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch(e) { console.error(e); }
    };

    return {
        // State
        slides,
        currentSlideIndex,
        currentSlide,
        saveStatus,
        isLoaded,
        currentProjectId,
        currentProjectName,
        savedProjects,
        isLoadingProjects,

        // Setters
        setSlides,
        setCurrentSlideIndex,

        // Actions
        updateSlide: handleUpdateSlide,
        addSlide: handleAddSlide,
        duplicateSlide: handleDuplicateSlide,
        deleteSlide: handleDeleteSlide,
        reorderSlide: handleReorderSlides,
        manualSave: () => saveToCloud(slides),

        // Styles
        applyTheme,
        applyTypography,
        randomizeLook,

        // Project Management
        startNewProject,
        loadRemoteProject,
        importProjectFile,
        downloadProjectFile,
        renameProject,
        deleteProject,
        duplicateProject,
        fetchProjects
    };
};

import React, { useRef, useState, useEffect } from 'react';
import EditorSidebar from './components/EditorSidebar';
import SlideRenderer from './components/SlideRenderer';
import PreviewControls from './components/PreviewControls';
import LoadingScreen from './components/LoadingScreen';
import HiddenExportRenderer from './components/HiddenExportRenderer';
import TopBar from './components/TopBar';
import ExportModal from './components/ExportModal';
import WelcomeScreen from './components/WelcomeScreen';

import { usePresentation } from './hooks/usePresentation';
import { usePlayback } from './hooks/usePlayback';
import { useScale } from './hooks/useScale';
import { useExportManager } from './hooks/useExportManager';

const App: React.FC = () => {
    // 1. Data & Persistence
    const {
        slides, currentSlideIndex, currentSlide, saveStatus, isLoaded,
        currentProjectName, savedProjects, isLoadingProjects,
        setCurrentSlideIndex, updateSlide, addSlide, duplicateSlide, deleteSlide, reorderSlide,
        manualSave, applyTheme, applyTypography, randomizeLook,
        startNewProject, importProjectFile, downloadProjectFile, 
        loadRemoteProject, renameProject, deleteProject, duplicateProject, fetchProjects
    } = usePresentation();

    // 2. Playback
    const { isPlaying, progress, togglePlay, scrub } = usePlayback(currentSlide?.duration);

    // 3. Render Helpers
    const containerRef = useRef<HTMLDivElement>(null);
    const scale = useScale(containerRef);

    // 4. Export Management
    const hiddenExportRef = useRef<HTMLDivElement>(null);
    const exportManager = useExportManager(slides, currentSlide, hiddenExportRef);

    // 5. Welcome Screen State
    const [showWelcomeScreen, setShowWelcomeScreen] = useState(true);

    // Automatically hide welcome screen when a project loads successfully
    useEffect(() => {
        if (slides.length > 0 && isLoaded) {
            // Note: We might want to keep it open initially until explicit selection
            // But if user clicks 'New' or 'Load', we should close it.
        }
    }, [slides, isLoaded]);

    const handleNewProject = () => {
        startNewProject();
        setShowWelcomeScreen(false);
    };

    const handleLoadProject = (id: string | number) => {
        loadRemoteProject(id);
        setShowWelcomeScreen(false);
    };

    const handleImportProject = (file: File) => {
        importProjectFile(file);
        setShowWelcomeScreen(false);
    };

    // If still loading initial state
    if (!isLoaded && !currentSlide && !showWelcomeScreen) return <LoadingScreen />;

    return (
        <div className="flex h-screen w-screen bg-[#050505] text-white flex-col relative">

            <WelcomeScreen 
                isOpen={showWelcomeScreen}
                onClose={() => setShowWelcomeScreen(false)}
                recentProjects={savedProjects}
                isLoadingProjects={isLoadingProjects}
                onNewProject={handleNewProject}
                onLoadProject={handleLoadProject}
                onImportProject={handleImportProject}
                onRenameProject={renameProject}
                onDeleteProject={deleteProject}
                onDuplicateProject={duplicateProject}
            />

            {/* Hidden Renderer for Export Operations */}
            <HiddenExportRenderer 
                ref={hiddenExportRef} 
                slide={exportManager.exportingSlide || currentSlide} 
                progress={exportManager.exportRenderProgress} 
            />

            {/* Top Navigation Bar */}
            <TopBar 
                currentSlide={currentSlide}
                currentProjectName={currentProjectName}
                saveStatus={saveStatus}
                isExporting={exportManager.isExporting}
                onApplyTheme={applyTheme}
                onApplyTypography={applyTypography}
                onRandomize={randomizeLook}
                onManualSave={manualSave}
                onNewProject={handleNewProject}
                onLoadProject={handleImportProject} // Top bar 'Project > Open' now maps to importing local file mostly
                onSaveProject={downloadProjectFile}
                onOpenExport={exportManager.openExportModal}
                onOpenWelcome={() => { fetchProjects(); setShowWelcomeScreen(true); }}
            />

            {/* Main Workspace */}
            <div className="flex-1 flex overflow-hidden">
                {/* Left: Preview Area */}
                <div className="flex-1 relative bg-[#050505] flex items-center justify-center overflow-hidden" ref={containerRef}>
                    <div className="relative shadow-2xl shadow-black">
                        {/* We reset key when critical slide props change to restart animations if needed, mostly handled by SlideRenderer internal logic though */}
                        <SlideRenderer 
                            key={`${currentSlide?.id}-${currentSlide?.textTransition}`} 
                            data={currentSlide || slides[0]} 
                            scale={scale}
                            progress={progress}
                        />
                    </div>

                    <PreviewControls 
                        currentSlideIndex={currentSlideIndex + 1} 
                        totalSlides={slides.length} 
                        onNext={() => currentSlideIndex < slides.length - 1 && setCurrentSlideIndex(currentSlideIndex + 1)} 
                        onPrev={() => currentSlideIndex > 0 && setCurrentSlideIndex(currentSlideIndex - 1)} 
                        isPlaying={isPlaying}
                        onTogglePlay={togglePlay}
                        progress={progress}
                        onScrub={scrub}
                    />
                </div>

                {/* Right: Editor Sidebar */}
                <EditorSidebar 
                    slides={slides}
                    currentSlideIndex={currentSlideIndex}
                    onUpdateSlide={updateSlide}
                    onAddSlide={addSlide}
                    onDuplicateSlide={duplicateSlide}
                    onDeleteSlide={deleteSlide}
                    onSelectSlide={setCurrentSlideIndex}
                    onReorderSlides={reorderSlide}
                />
            </div>

            {/* Export Modal */}
            <ExportModal 
                isOpen={exportManager.isExportModalOpen}
                onClose={() => exportManager.setIsExportModalOpen(false)}
                tab={exportManager.exportModalTab}
                setTab={exportManager.setExportModalTab}
                scope={exportManager.exportScope}
                slideCount={slides.length}
                currentSlideBadge={currentSlide?.badge || ""}
                quality={exportManager.exportQuality}
                setQuality={exportManager.setExportQuality}
                bitrate={exportManager.exportBitrate}
                setBitrate={exportManager.setExportBitrate}
                format={exportManager.exportFormat}
                setFormat={exportManager.setExportFormat}
                imageFormat={exportManager.exportImageFormat}
                setImageFormat={exportManager.setExportImageFormat}
                isExporting={exportManager.isExporting}
                progress={exportManager.exportProgressStatus}
                queue={exportManager.exportQueue}
                onQueue={exportManager.queueExport}
                onStart={() => exportManager.executeExport()}
                onProcessQueue={exportManager.processQueue}
                onDeleteJob={exportManager.deleteJob}
            />

        </div>
    );
};

export default App;

import React, { useState, useRef } from 'react';
import { LayoutTemplate, Plus, Upload, FileText, Calendar, Trash2, Edit2, Search, X, Loader2, Copy } from 'lucide-react';
import { ProjectMetadata } from '../types';

interface WelcomeScreenProps {
    isOpen: boolean;
    onClose: () => void;
    recentProjects: ProjectMetadata[];
    isLoadingProjects: boolean;
    onNewProject: () => void;
    onLoadProject: (id: string | number) => void;
    onImportProject: (file: File) => void;
    onRenameProject: (id: string | number, newName: string) => void;
    onDeleteProject: (id: string | number) => void;
    onDuplicateProject: (id: string | number) => void;
}

const WelcomeScreen: React.FC<WelcomeScreenProps> = ({
    isOpen, onClose,
    recentProjects, isLoadingProjects,
    onNewProject, onLoadProject, onImportProject, onRenameProject, onDeleteProject, onDuplicateProject
}) => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [editingId, setEditingId] = useState<string | number | null>(null);
    const [editName, setEditName] = useState('');

    if (!isOpen) return null;

    const filteredProjects = recentProjects.filter(p => 
        p.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const handleStartRename = (project: ProjectMetadata) => {
        setEditingId(project.id);
        setEditName(project.name);
    };

    const handleFinishRename = () => {
        if (editingId && editName.trim()) {
            onRenameProject(editingId, editName);
        }
        setEditingId(null);
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') handleFinishRename();
        if (e.key === 'Escape') setEditingId(null);
    };

    return (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-[#050505]/95 backdrop-blur-md animate-in fade-in duration-300">
            <div className="w-full max-w-5xl h-[80vh] bg-[#101010] border border-white/10 rounded-2xl shadow-2xl flex overflow-hidden">

                {/* Left Sidebar: Actions */}
                <div className="w-80 bg-[#161616] border-r border-white/5 p-8 flex flex-col gap-8">
                    <div className="flex items-center gap-3 mb-4">
                        <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
                            <LayoutTemplate size={24} className="text-white" />
                        </div>
                        <div>
                            <h1 className="font-bold text-xl tracking-tight text-white">SlideForge</h1>
                            <p className="text-xs text-gray-500">Presentation Editor</p>
                        </div>
                    </div>

                    <div className="space-y-4">
                        <button 
                            onClick={onNewProject}
                            className="w-full py-4 px-6 bg-white text-black font-bold rounded-xl hover:bg-gray-200 transition-colors flex items-center gap-3 shadow-lg group"
                        >
                            <div className="w-8 h-8 rounded-full bg-black/10 flex items-center justify-center group-hover:scale-110 transition-transform">
                                <Plus size={18} />
                            </div>
                            <span>New Project</span>
                        </button>

                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            className="w-full py-4 px-6 bg-white/5 border border-white/10 text-gray-300 font-medium rounded-xl hover:bg-white/10 hover:text-white transition-all flex items-center gap-3 group"
                        >
                            <div className="w-8 h-8 rounded-full bg-white/5 flex items-center justify-center group-hover:bg-white/10 transition-colors">
                                <Upload size={18} />
                            </div>
                            <span>Import JSON</span>
                            <input 
                                type="file" 
                                ref={fileInputRef} 
                                accept=".json" 
                                className="hidden" 
                                onChange={(e) => {
                                    if(e.target.files?.[0]) onImportProject(e.target.files[0]);
                                }}
                            />
                        </button>
                    </div>

                    <div className="mt-auto">
                        <button onClick={onClose} className="text-gray-500 hover:text-white text-sm transition-colors flex items-center gap-2">
                           <X size={16} /> Close & Return to Editor
                        </button>
                    </div>
                </div>

                {/* Right Content: Recent Files */}
                <div className="flex-1 flex flex-col bg-[#0a0a0a]">
                    <div className="p-8 pb-4 border-b border-white/5 flex items-center justify-between">
                        <h2 className="text-2xl font-bold text-white">Recent Projects</h2>
                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                            <input 
                                type="text" 
                                placeholder="Search projects..." 
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="bg-[#1a1a1a] border border-white/10 rounded-lg pl-10 pr-4 py-2 text-sm text-white focus:outline-none focus:border-indigo-500/50 w-64 transition-all"
                            />
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
                        {isLoadingProjects ? (
                            <div className="flex flex-col items-center justify-center h-64 text-gray-500 gap-3">
                                <Loader2 size={32} className="animate-spin text-indigo-500" />
                                <p>Syncing with cloud...</p>
                            </div>
                        ) : filteredProjects.length === 0 ? (
                            <div className="flex flex-col items-center justify-center h-64 text-gray-600 border-2 border-dashed border-white/5 rounded-xl">
                                <FileText size={48} className="mb-4 opacity-20" />
                                <p className="text-lg font-medium">No projects found</p>
                                <p className="text-sm">Create a new one or import a file to get started.</p>
                            </div>
                        ) : (
                            <div className="grid grid-cols-1 gap-3">
                                {filteredProjects.map((project) => (
                                    <div 
                                        key={project.id} 
