import React, { useRef, useState, useEffect } from 'react';
import EditorSidebar from './components/EditorSidebar';
import SlideRenderer from './components/SlideRenderer';
import PreviewControls from './components/PreviewControls';
import LoadingScreen from './components/LoadingScreen';
import HiddenExportRenderer from './components/HiddenExportRenderer';
import TopBar from './components/TopBar';
import ExportModal from './components/ExportModal';
import WelcomeScreen from './components/WelcomeScreen';

import { usePresentation } from './hooks/usePresentation';
import { usePlayback } from './hooks/usePlayback';
import { useScale } from './hooks/useScale';
import { useExportManager } from './hooks/useExportManager';

const App: React.FC = () => {
    // 1. Data & Persistence
    const {
        slides, currentSlideIndex, currentSlide, saveStatus, isLoaded,
        currentProjectName, savedProjects, isLoadingProjects,
        setCurrentSlideIndex, updateSlide, addSlide, duplicateSlide, deleteSlide, reorderSlide,
        manualSave, applyTheme, applyTypography, randomizeLook,
        startNewProject, importProjectFile, downloadProjectFile, 
        loadRemoteProject, renameProject, toggleArchiveStatus, duplicateProject, fetchProjects
    } = usePresentation();

    // 2. Playback
    const { isPlaying, progress, togglePlay, scrub } = usePlayback(currentSlide?.duration);

    // 3. Render Helpers
    const containerRef = useRef<HTMLDivElement>(null);
    const scale = useScale(containerRef);

    // 4. Export Management
    const hiddenExportRef = useRef<HTMLDivElement>(null);
    const exportManager = useExportManager(slides, currentSlide, hiddenExportRef);

    // 5. Welcome Screen State
    const [showWelcomeScreen, setShowWelcomeScreen] = useState(true);

    // Automatically hide welcome screen when a project loads successfully
    useEffect(() => {
        if (slides.length > 0 && isLoaded) {
            // Note: We might want to keep it open initially until explicit selection
            // But if user clicks 'New' or 'Load', we should close it.
        }
    }, [slides, isLoaded]);

    const handleNewProject = () => {
        startNewProject();
        setShowWelcomeScreen(false);
    };

    const handleLoadProject = (id: string | number) => {
        loadRemoteProject(id);
        setShowWelcomeScreen(false);
    };

    const handleImportProject = (file: File) => {
        importProjectFile(file);
        setShowWelcomeScreen(false);
    };

    // If still loading initial state
    if (!isLoaded && !currentSlide && !showWelcomeScreen) return <LoadingScreen />;

    return (
        <div className="flex h-screen w-screen bg-[#050505] text-white flex-col relative">

            <WelcomeScreen 
                isOpen={showWelcomeScreen}
                onClose={() => setShowWelcomeScreen(false)}
                recentProjects={savedProjects}
                isLoadingProjects={isLoadingProjects}
                onNewProject={handleNewProject}
                onLoadProject={handleLoadProject}
                onImportProject={handleImportProject}
                onRenameProject={renameProject}
                onToggleArchive={toggleArchiveStatus}
                onDuplicateProject={duplicateProject}
            />

            {/* Hidden Renderer for Export Operations */}
            <HiddenExportRenderer 
                ref={hiddenExportRef} 
                slide={exportManager.exportingSlide || currentSlide} 
                progress={exportManager.exportRenderProgress} 
            />

            {/* Top Navigation Bar */}
            <TopBar 
                currentSlide={currentSlide}
                currentProjectName={currentProjectName}
                saveStatus={saveStatus}
                isExporting={exportManager.isExporting}
                onApplyTheme={applyTheme}
                onApplyTypography={applyTypography}
                onRandomize={randomizeLook}
                onManualSave={manualSave}
                onNewProject={handleNewProject}
                onLoadProject={handleImportProject} // Top bar 'Project > Open' now maps to importing local file mostly
                onSaveProject={downloadProjectFile}
                onOpenExport={exportManager.openExportModal}
                onOpenWelcome={() => { fetchProjects(); setShowWelcomeScreen(true); }}
            />

            {/* Main Workspace */}
            <div className="flex-1 flex overflow-hidden">
                {/* Left: Preview Area */}
                <div className="flex-1 relative bg-[#050505] flex items-center justify-center overflow-hidden" ref={containerRef}>
                    <div className="relative shadow-2xl shadow-black">
                        {/* We reset key when critical slide props change to restart animations if needed, mostly handled by SlideRenderer internal logic though */}
                        <SlideRenderer 
                            key={`${currentSlide?.id}-${currentSlide?.textTransition}`} 
                            data={currentSlide || slides[0]} 
                            scale={scale}
                            progress={progress}
                        />
                    </div>

                    <PreviewControls 
                        currentSlideIndex={currentSlideIndex + 1} 
                        totalSlides={slides.length} 
                        onNext={() => currentSlideIndex < slides.length - 1 && setCurrentSlideIndex(currentSlideIndex + 1)} 
                        onPrev={() => currentSlideIndex > 0 && setCurrentSlideIndex(currentSlideIndex - 1)} 
                        isPlaying={isPlaying}
                        onTogglePlay={togglePlay}
                        progress={progress}
                        onScrub={scrub}
                    />
                </div>

                {/* Right: Editor Sidebar */}
                <EditorSidebar 
                    slides={slides}
                    currentSlideIndex={currentSlideIndex}
                    onUpdateSlide={updateSlide}
                    onAddSlide={addSlide}
                    onDuplicateSlide={duplicateSlide}
                    onDeleteSlide={deleteSlide}
                    onSelectSlide={setCurrentSlideIndex}
                    onReorderSlides={reorderSlide}
                />
            </div>

            {/* Export Modal */}
            <ExportModal 
                isOpen={exportManager.isExportModalOpen}
                onClose={() => exportManager.setIsExportModalOpen(false)}
                tab={exportManager.exportModalTab}
                setTab={exportManager.setExportModalTab}
                scope={exportManager.exportScope}
                slideCount={slides.length}
                currentSlideBadge={currentSlide?.badge || ""}
                quality={exportManager.exportQuality}
                setQuality={exportManager.setExportQuality}
                bitrate={exportManager.exportBitrate}
                setBitrate={exportManager.setExportBitrate}
                format={exportManager.exportFormat}
                setFormat={exportManager.setExportFormat}
                imageFormat={exportManager.exportImageFormat}
                setImageFormat={exportManager.setExportImageFormat}
                isExporting={exportManager.isExporting}
                progress={exportManager.exportProgressStatus}
                queue={exportManager.exportQueue}
                onQueue={exportManager.queueExport}
                onStart={() => exportManager.executeExport()}
                onProcessQueue={exportManager.processQueue}
                onDeleteJob={exportManager.deleteJob}
            />

        </div>
    );
};

export default App;

import { useState, useEffect, useRef } from 'react';
import { SlideData, INITIAL_SLIDE, createNewSlide, SlideLayout, ThemeId, TypographyId, THEMES, TYPOGRAPHY_STYLES, ProjectMetadata } from '../types';
import { supabase } from '../services/supabaseClient';

export const usePresentation = () => {
    // Current Project State
    const [currentProjectId, setCurrentProjectId] = useState<string | number | null>(null);
    const [currentProjectName, setCurrentProjectName] = useState<string>("Untitled Project");
    const [slides, setSlides] = useState<SlideData[]>([INITIAL_SLIDE]);
    const [currentSlideIndex, setCurrentSlideIndex] = useState(0);

    // App State
    const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');
    const [isLoaded, setIsLoaded] = useState(false);
    const isFirstLoad = useRef(true);

    // Project List State
    const [savedProjects, setSavedProjects] = useState<ProjectMetadata[]>([]);
    const [isLoadingProjects, setIsLoadingProjects] = useState(false);

    const currentSlide = slides[currentSlideIndex] || slides[0];

    // --- Persistence Logic ---

    // Fetch Project List
    const fetchProjects = async () => {
        setIsLoadingProjects(true);
        try {
            // Select relevant fields. Order by updated_at descending
            const { data, error } = await supabase
                .from('presentations')
                .select('id, name, updated_at')
                .order('updated_at', { ascending: false });

            if (error) throw error;
            if (data) {
                setSavedProjects(data as ProjectMetadata[]);
            }
        } catch (e) {
            console.error("Failed to fetch projects list:", e);
        } finally {
            setIsLoadingProjects(false);
        }
    };

    // Initial Load of Project List
    useEffect(() => {
        fetchProjects();
        setIsLoaded(true);
        setTimeout(() => { isFirstLoad.current = false; }, 500);
    }, []);

    // Load Specific Project
    const loadRemoteProject = async (id: string | number) => {
        setIsLoaded(false);
        try {
            const { data, error } = await supabase
                .from('presentations')
                .select('*')
                .eq('id', id)
                .single();

            if (error) throw error;
            if (data) {
                // If opening an archived project, visually strip the tag for the editor title
                const cleanName = data.name.replace('[ARCHIVED] ', '');

                setSlides(data.slides || [INITIAL_SLIDE]);
                setCurrentProjectId(data.id);
                setCurrentProjectName(cleanName);
                setCurrentSlideIndex(0);
            }
        } catch (e) {
            console.error("Failed to load project:", e);
            alert("Could not load project.");
            fetchProjects(); // Refresh list to verify
        } finally {
            setIsLoaded(true);
        }
    };

    // Create New Remote Project
    const createNewRemoteProject = async (name: string, initialSlides: SlideData[]) => {
        setIsLoaded(false);
        try {
            const { data, error } = await supabase
                .from('presentations')
                .insert([{
                    name: name,
                    slides: initialSlides,
                    updated_at: new Date().toISOString()
                }])
                .select()
                .single();

            if (error) throw error;
            if (data) {
                setCurrentProjectId(data.id);
                setCurrentProjectName(data.name);
                setSlides(initialSlides);
                setCurrentSlideIndex(0);
                fetchProjects(); // Refresh list
            }
        } catch (e) {
            console.error("Failed to create project:", e);
            // Fallback for offline or error: just set state
            setSlides(initialSlides);
            setCurrentProjectName(name);
            setCurrentProjectId(Date.now()); // Temp ID
            setCurrentSlideIndex(0);
        } finally {
            setIsLoaded(true);
        }
    };

    // Duplicate Project
    const duplicateProject = async (id: string | number) => {
        try {
            const { data: original, error: fetchError } = await supabase
                .from('presentations')
                .select('*')
                .eq('id', id)
                .single();

            if (fetchError) throw fetchError;
            if (!original) return;

            // Ensure we don't duplicate the archived tag if it exists
            const rawName = original.name.replace('[ARCHIVED] ', '');
            const newName = `Copy of ${rawName}`;

            const { error: insertError } = await supabase
                .from('presentations')
                .insert([{
                    name: newName,
                    slides: original.slides,
                    updated_at: new Date().toISOString()
                }]);

            if (insertError) throw insertError;
            fetchProjects();
        } catch (e) {
            console.error("Failed to duplicate:", e);
        }
    };

    // Save Helper
    const saveToCloud = async (slidesToSave: SlideData[]) => {
        if (!currentProjectId) return; 

        setSaveStatus('saving');
        try {
            // Ensure we preserve the [ARCHIVED] tag if it exists in the list but we are editing it
            // Actually, usually if you edit an archived project, it stays archived until you unarchive it.
            // We use the currentProjectName state. If the user loaded it, we stripped the tag in loadRemoteProject.
            // So saving it might unarchive it if we are not careful. 
            // For simplicity, we save with the current name in state.

            const { error } = await supabase
                .from('presentations')
                .upsert({ 
                    id: currentProjectId, 
                    name: currentProjectName,
                    slides: slidesToSave,
                    updated_at: new Date().toISOString()
                });

            if (error) throw error;
            setSaveStatus('saved');
            setTimeout(() => setSaveStatus('idle'), 2000);
            fetchProjects(); 
        } catch (error: any) {
            console.error("Failed to save to Supabase:", error);
            setSaveStatus('error');
        }
    };

    // Rename Project
    const renameProject = async (id: string | number, newName: string) => {
        try {
            const { error } = await supabase
                .from('presentations')
                .update({ name: newName })
                .eq('id', id);

            if (error) throw error;

            if (id === currentProjectId) {
                setCurrentProjectName(newName);
            }
            fetchProjects();
        } catch (e) {
            console.error("Failed to rename:", e);
        }
    };

    // Toggle Archive Status (Replaces Delete)
    const toggleArchiveStatus = async (id: string | number) => {
        const project = savedProjects.find(p => p.id === id);
        if (!project) return;

        const isArchived = project.name.startsWith('[ARCHIVED] ');
        const newName = isArchived 
            ? project.name.replace('[ARCHIVED] ', '') 
            : `[ARCHIVED] ${project.name}`;

        // Optimistic Update
        const previousProjects = [...savedProjects];
        setSavedProjects(prev => prev.map(p => 
            p.id === id ? { ...p, name: newName } : p
        ));

        try {
            const { error } = await supabase
                .from('presentations')
                .update({ name: newName })
                .eq('id', id);

            if (error) throw error;

            // If we archived the currently open project, update the name in editor to reflect logic if needed
            // but usually we just leave the editor as is.

        } catch (e: any) {
            console.error("Failed to toggle archive:", e);
            alert("Failed to update project status.");
            setSavedProjects(previousProjects);
        }
    };

    // Auto-Save
    useEffect(() => {
        if (!isLoaded || isFirstLoad.current || !currentProjectId) return;
        const timeoutId = setTimeout(() => {
            saveToCloud(slides);
        }, 2000);
        return () => clearTimeout(timeoutId);
    }, [slides, isLoaded, currentProjectId, currentProjectName]);


    // --- Slide Operations ---

    const handleUpdateSlide = (updatedSlide: SlideData) => {
        const oldSlide = slides[currentSlideIndex];
        let newSlides = slides.map((s, index) => index === currentSlideIndex ? updatedSlide : s);

        // Apply Global changes logic (Keep Theme and Typography global)
        if (oldSlide.theme !== updatedSlide.theme) {
            newSlides = newSlides.map(s => ({ ...s, theme: updatedSlide.theme }));
        }
        if (oldSlide.typography !== updatedSlide.typography) {
            newSlides = newSlides.map(s => ({ ...s, typography: updatedSlide.typography }));
        }

        // Transitions are now per-slide only (removed global sync for transitions)

        setSlides(newSlides);
    };

    const handleAddSlide = (layout: SlideLayout = 'text-image') => {
        const newSlide = createNewSlide(layout);
        const refSlide = slides[currentSlideIndex] || slides[0];
        // Inherit styles
        newSlide.theme = refSlide.theme || 'cyber-future';
        newSlide.typography = refSlide.typography || 'modern-sans';
        newSlide.textTransition = refSlide.textTransition || 'slide-up';
        newSlide.imageTransition = refSlide.imageTransition || 'zoom-in';
        newSlide.textOutroTransition = refSlide.textOutroTransition || 'none';
        newSlide.imageOutroTransition = refSlide.imageOutroTransition || 'none';

        const lastSlide = slides[slides.length - 1];
        if (lastSlide && lastSlide.badge.startsWith('Step ')) {
            const num = parseInt(lastSlide.badge.split(' ')[1]);
            if (!isNaN(num)) newSlide.badge = `Step ${num + 1}`;
        }

        setSlides([...slides, newSlide]);
        setCurrentSlideIndex(slides.length);
    };

    const handleDuplicateSlide = (index: number) => {
        const slide = slides[index];
        if (!slide) return;
        const newSlide = { ...slide, id: Date.now().toString() };
        const newSlides = [...slides];
        newSlides.splice(index + 1, 0, newSlide);
        setSlides(newSlides);
        setCurrentSlideIndex(index + 1);
    };

    const handleDeleteSlide = (index: number) => {
        if (slides.length <= 1) return;
        const newSlides = slides.filter((_, i) => i !== index);
        setSlides(newSlides);
        if (currentSlideIndex >= index && currentSlideIndex > 0) {
            setCurrentSlideIndex(currentSlideIndex - 1);
        } else if (currentSlideIndex >= newSlides.length) {
            setCurrentSlideIndex(newSlides.length - 1);
        }
    };

    const handleReorderSlides = (from: number, to: number) => {
        if (from === to) return;
        const newSlides = [...slides];
        const [moved] = newSlides.splice(from, 1);
        newSlides.splice(to, 0, moved);
        setSlides(newSlides);

        if (currentSlideIndex === from) setCurrentSlideIndex(to);
        else if (from < currentSlideIndex && to >= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex - 1);
        else if (from > currentSlideIndex && to <= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex + 1);
    };

    const applyTheme = (id: ThemeId) => setSlides(slides.map(s => ({ ...s, theme: id })));
    const applyTypography = (id: TypographyId) => setSlides(slides.map(s => ({ ...s, typography: id })));

    const randomizeLook = () => {
        const t = THEMES[Math.floor(Math.random() * THEMES.length)];
        const f = TYPOGRAPHY_STYLES[Math.floor(Math.random() * TYPOGRAPHY_STYLES.length)];
        setSlides(slides.map(s => ({ ...s, theme: t.id, typography: f.id })));
    };

    // --- New Project Management ---

    const startNewProject = () => {
        const dateStr = new Date().toLocaleString();
        const name = `Project - ${dateStr}`;
        const freshSlide = createNewSlide('text-image');

        createNewRemoteProject(name, [freshSlide]);
    };

    const importProjectFile = (file: File) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const json = JSON.parse(e.target?.result as string);
                if (Array.isArray(json) && json.length > 0 && json[0].id) {
                    const dateStr = new Date().toLocaleString();
                    const name = `Imported - ${dateStr}`;
                    createNewRemoteProject(name, json as SlideData[]);
                } else {
                    alert("Invalid project file.");
                }
            } catch (err) {
                console.error(err);
                alert("Failed to parse project file.");
            }
        };
        reader.readAsText(file);
    };

    const downloadProjectFile = () => {
        try {
            const blob = new Blob([JSON.stringify(slides, null, 2)], { type: "application/json" });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${currentProjectName.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch(e) { console.error(e); }
    };

    return {
        // State
        slides,
        currentSlideIndex,
        currentSlide,
        saveStatus,
        isLoaded,
        currentProjectId,
        currentProjectName,
        savedProjects,
        isLoadingProjects,

        // Setters
        setSlides,
        setCurrentSlideIndex,

        // Actions
        updateSlide: handleUpdateSlide,
        addSlide: handleAddSlide,
        duplicateSlide: handleDuplicateSlide,
        deleteSlide: handleDeleteSlide,
        reorderSlide: handleReorderSlides,
        manualSave: () => saveToCloud(slides),

        // Styles
        applyTheme,
        applyTypography,
        randomizeLook,

        // Project Management
        startNewProject,
        loadRemoteProject,
        importProjectFile,
        downloadProjectFile,
        renameProject,
        toggleArchiveStatus, // New function exposed
        duplicateProject,
        fetchProjects
    };
};

import React, { useState, useRef } from 'react';
import { SlideData, ExportJob } from '../types';
import * as Mp4Muxer from 'mp4-muxer';
import { toCanvas } from 'html-to-image';
import JSZip from 'jszip';

export const useExportManager = (
    slides: SlideData[], 
    currentSlide: SlideData,
    exportContainerRef: React.RefObject<HTMLDivElement | null>
) => {
    // UI State
    const [isExportModalOpen, setIsExportModalOpen] = useState(false);
    const [exportModalTab, setExportModalTab] = useState<'settings' | 'queue'>('settings');

    // Settings State (Local to manager)
    const [exportScope, setExportScope] = useState<'current' | 'all'>('current');
    const [exportQuality, setExportQuality] = useState<'720p' | '1080p' | '4k'>('1080p');
    const [exportBitrate, setExportBitrate] = useState<'low' | 'medium' | 'high'>('medium');
    const [exportFormat, setExportFormat] = useState<'mp4' | 'zip' | 'folder'>('mp4');
    const [exportImageFormat, setExportImageFormat] = useState<'jpeg' | 'png'>('jpeg');

    // Execution State
    const [exportQueue, setExportQueue] = useState<ExportJob[]>([]);
    const [isExporting, setIsExporting] = useState(false);
    const [exportProgressStatus, setExportProgressStatus] = useState(0);
    const [exportingSlide, setExportingSlide] = useState<SlideData | null>(null);
    const [exportRenderProgress, setExportRenderProgress] = useState(0);

    const openExportModal = (scope: 'current' | 'all') => {
        setExportScope(scope);
        setIsExportModalOpen(true);
        setExportModalTab('settings');
    };

    const queueExport = () => {
        const slidesSnapshot = exportScope === 'current' ? [currentSlide] : [...slides];
        const newJob: ExportJob = {
            id: Date.now().toString(),
            status: 'pending',
            createdAt: Date.now(),
            scope: exportScope,
            slides: JSON.parse(JSON.stringify(slidesSnapshot)),
            quality: exportQuality,
            bitrate: exportBitrate,
            format: exportFormat,
            imageFormat: exportImageFormat
        };
        setExportQueue([...exportQueue, newJob]);
        setExportModalTab('queue');
    };

    const processQueue = async () => {
        if (isExporting) return;
        const pending = exportQueue.filter(j => j.status === 'pending');
        if (pending.length === 0) return;

        for (const job of pending) {
            setExportQueue(prev => prev.map(j => j.id === job.id ? { ...j, status: 'processing' } : j));
            try {
                await executeExport(job);
                setExportQueue(prev => prev.map(j => j.id === job.id ? { ...j, status: 'completed' } : j));
            } catch (e) {
                console.error(e);
                setExportQueue(prev => prev.map(j => j.id === job.id ? { ...j, status: 'failed' } : j));
            }
            await new Promise(r => setTimeout(r, 1000));
        }
        setIsExporting(false);
        setExportingSlide(null);
        setExportProgressStatus(0);
    };

    const executeExport = async (job?: ExportJob) => {
        if (!job && isExporting) return;
        if (!exportContainerRef.current) return;

        setIsExporting(true);
        setExportProgressStatus(0);

        const cfgQuality = job ? job.quality : exportQuality;
        const cfgBitrate = job ? job.bitrate : exportBitrate;
        const cfgFormat = job ? job.format : exportFormat;
        const cfgScope = job ? job.scope : exportScope;
        const cfgSlides = job ? job.slides : (exportScope === 'current' ? [currentSlide] : slides);
        const cfgImageFormat = job ? job.imageFormat : exportImageFormat;

        const FPS = 30;
        let WIDTH = 1920;
        let HEIGHT = 1080;
        let bitRate = 5_000_000;

        if (cfgQuality === '720p') {
            WIDTH = 1280; HEIGHT = 720;
            bitRate = cfgBitrate === 'low' ? 1.5e6 : cfgBitrate === 'medium' ? 2.5e6 : 4e6;
        } else if (cfgQuality === '1080p') {
            WIDTH = 1920; HEIGHT = 1080;
            bitRate = cfgBitrate === 'low' ? 3e6 : cfgBitrate === 'medium' ? 5e6 : 8e6;
        } else if (cfgQuality === '4k') {
            WIDTH = 3840; HEIGHT = 2160;
            bitRate = cfgBitrate === 'low' ? 8e6 : cfgBitrate === 'medium' ? 12e6 : 20e6;
        }

        // --- BACKGROUND TIMER WORKER SETUP ---
        // Browsers throttle setTimeout to 1s in background tabs. 
        // We use a Web Worker (which is less throttled) to drive the render loop.
        const workerBlob = new Blob([
            `self.onmessage = function(e) { setTimeout(function() { self.postMessage('tick'); }, e.data); }`
        ], { type: 'application/javascript' });
        const workerUrl = URL.createObjectURL(workerBlob);
        const timerWorker = new Worker(workerUrl);

        // Helper to wait using the worker
        const backgroundDelay = (ms: number) => new Promise<void>(resolve => {
            timerWorker.onmessage = () => {
                timerWorker.onmessage = null; // Clean up
                resolve();
            };
            timerWorker.postMessage(ms);
        });

        try {
            let muxer: any = null;
            let videoEncoder: VideoEncoder | null = null;
            let zip: JSZip | null = null;

            // Generate a safe folder name for this export
            const baseName = cfgScope === 'current' && cfgSlides.length === 1 ? `slide-${cfgSlides[0].badge.replace(/\s+/g,'_')}` : `presentation`;
            const timestamp = Date.now();
            const folderName = `${baseName}_${timestamp}`;

            if (cfgFormat === 'mp4') {
                muxer = new Mp4Muxer.Muxer({
                    target: new Mp4Muxer.ArrayBufferTarget(),
                    video: { codec: 'avc', width: WIDTH, height: HEIGHT },
                    fastStart: 'in-memory',
                    firstTimestampBehavior: 'offset',
                });
                const codecStr = cfgQuality === '4k' ? 'avc1.640033' : 'avc1.4d002a';
                videoEncoder = new VideoEncoder({
                    output: (chunk, meta) => muxer.addVideoChunk(chunk, meta),
                    error: (e) => console.error(e)
                });
                videoEncoder.configure({ codec: codecStr, width: WIDTH, height: HEIGHT, bitrate: bitRate });
            } else if (cfgFormat === 'zip') {
                zip = new JSZip();
            }

            let totalExportFrames = 0;
            cfgSlides.forEach(s => totalExportFrames += Math.ceil((s.duration || 5) * FPS));
            let globalFrameCount = 0;

            for (const slide of cfgSlides) {
                setExportingSlide(slide);
                // Wait for React to render the new slide in the hidden container
                await backgroundDelay(250);

                const duration = slide.duration || 5;
                const frames = Math.ceil(duration * FPS);

                for (let i = 0; i < frames; i++) {
                    const prog = (i / (frames - 1)) * 100;
                    setExportRenderProgress(prog);
                    setExportProgressStatus(Math.round((globalFrameCount / totalExportFrames) * 100));

                    // Throttle with background worker instead of setTimeout
                    // 10ms is sufficient to let the UI update but fast enough for export
                    await backgroundDelay(10);

                    if (exportContainerRef.current) {
                        try {
                            const canvas = await toCanvas(exportContainerRef.current, {
                                width: WIDTH, height: HEIGHT, pixelRatio: 1, cacheBust: true,
                                style: { transform: 'none', transformOrigin: 'top left' },
                                fontEmbedCSS: '',
                            });

                            if (cfgFormat === 'mp4' && videoEncoder) {
                                const frame = new VideoFrame(canvas, { timestamp: (globalFrameCount * 1e6) / FPS, duration: 1e6 / FPS });
                                videoEncoder.encode(frame);
                                frame.close();
                            } else if (cfgFormat === 'zip' && zip) {
                                const mime = cfgImageFormat === 'jpeg' ? 'image/jpeg' : 'image/png';
                                const q = cfgImageFormat === 'jpeg' ? 0.9 : undefined;
                                const ext = cfgImageFormat === 'jpeg' ? 'jpg' : 'png';
                                const blob = await new Promise<Blob | null>(r => canvas.toBlob(r, mime, q));
                                if (blob) zip.file(`frame_${String(globalFrameCount).padStart(5,'0')}.${ext}`, blob);
                            } else if (cfgFormat === 'folder') {
                                // DIRECT FOLDER OUTPUT VIA EXTENSION
                                const mime = cfgImageFormat === 'jpeg' ? 'image/jpeg' : 'image/png';
                                const q = cfgImageFormat === 'jpeg' ? 0.9 : undefined;
                                const ext = cfgImageFormat === 'jpeg' ? 'jpg' : 'png';

                                const blob = await new Promise<Blob | null>(r => canvas.toBlob(r, mime, q));
                                if (blob) {
                                    const url = URL.createObjectURL(blob);
                                    // Send to extension
                                    window.postMessage({
                                        type: 'SLIDEFORGE_DOWNLOAD',
                                        payload: {
                                            url: url,
                                            filename: `${folderName}/frame_${String(globalFrameCount).padStart(5,'0')}.${ext}`
                                        }
                                    }, '*');

                                    // Clean up object URL after a delay to ensure extension read it
                                    setTimeout(() => URL.revokeObjectURL(url), 5000);

                                    // Slow down explicit loop for Folder export to prevent browser choking on messaging
                                    await backgroundDelay(50);
                                }
                            }
                        } catch (err) { console.warn(err); }
                    }
                    globalFrameCount++;
                }
            }

            // Finalization phase
            if (cfgFormat === 'mp4' && videoEncoder && muxer) {
                await videoEncoder.flush();
                muxer.finalize();
                const blob = new Blob([muxer.target.buffer], { type: 'video/mp4' });
                const filename = `${baseName}_${cfgQuality}.mp4`;
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url; a.download = filename;
                document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
            } else if (cfgFormat === 'zip' && zip) {
                const blob = await zip.generateAsync({ type: "blob" });
                const filename = `${baseName}_frames.zip`;
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url; a.download = filename;
                document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
            } else if (cfgFormat === 'folder') {
                // No finalization needed for folder export, as frames are streamed.
                await backgroundDelay(500);
            }

            if (!job) {
                setTimeout(() => { setIsExportModalOpen(false); setIsExporting(false); setExportProgressStatus(0); }, 1000);
            }
        } catch (e: any) {
            console.error("Export Failed", e);
            if (!job) alert(`Export failed: ${e.message}`);
            else throw e;
        } finally {
            // Cleanup Worker
            timerWorker.terminate();
            URL.revokeObjectURL(workerUrl);

            if (!job) { setExportingSlide(null); setIsExporting(false); }
        }
    };

    return {
        // UI State
        isExportModalOpen, setIsExportModalOpen,
        exportModalTab, setExportModalTab,
        // Settings State setters
        setExportQuality, setExportBitrate, setExportFormat, setExportImageFormat,
        // Settings State getters
        exportScope, exportQuality, exportBitrate, exportFormat, exportImageFormat,
        // Queue & Status
        exportQueue, setExportQueue,
        isExporting,
        exportProgressStatus,
        exportingSlide,
        exportRenderProgress,
        // Actions
        openExportModal,
        queueExport,
        processQueue,
        executeExport, // Direct start
        deleteJob: (id: string) => setExportQueue(q => q.filter(j => j.id !== id))
    };
};

