import { useState, useEffect, useRef } from 'react';

export const usePlayback = (duration: number = 5) => {
    const [isPlaying, setIsPlaying] = useState(false);
    const [progress, setProgress] = useState(0);

    // NOTE: We removed the automatic useEffect reset here to allow 
    // the parent App to control exactly when to reset (e.g. don't reset during global seek)

    const reset = () => {
        setIsPlaying(false);
        // Default start at a visible point (e.g., 20% or 1s in)
        const startSec = 1;
        const startProg = duration > 0 ? (startSec / duration) * 100 : 0;
        setProgress(Math.min(startProg, 100));
    };

    // Animation Loop
    useEffect(() => {
        let rafId: number;
        let lastTime: number | undefined;

        const animate = (time: number) => {
            if (lastTime !== undefined) {
                const delta = (time - lastTime) / 1000;
                setProgress(prev => {
                    const inc = (delta / duration) * 100;
                    const next = prev + inc;
                    if (next >= 100) {
                        setIsPlaying(false);
                        return 100; // Cap at 100
                    }
                    return next;
                });
            }
            lastTime = time;
            if (isPlaying) rafId = requestAnimationFrame(animate);
        };

        if (isPlaying) rafId = requestAnimationFrame(animate);
        else lastTime = undefined;

        return () => { if (rafId) cancelAnimationFrame(rafId); };
    }, [isPlaying, duration]);

    return {
        isPlaying,
        progress,
        togglePlay: () => setIsPlaying(!isPlaying),
        scrub: (p: number) => {
            setIsPlaying(false);
            setProgress(p);
        },
        reset // Expose reset for manual slide changes
    };
};

import React, { useRef, useMemo } from 'react';
import { SlideData } from '../types';

interface GlobalTimelineProps {
    slides: SlideData[];
    currentSlideIndex: number;
    currentSlideProgress: number; // 0-100
    onSeek: (totalProgress: number) => void; // 0-100
    onSeekStart?: () => void;
    onSeekEnd?: () => void;
}

const GlobalTimeline: React.FC<GlobalTimelineProps> = ({
    slides,
    currentSlideIndex,
    currentSlideProgress,
    onSeek,
    onSeekStart,
    onSeekEnd
}) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const isDragging = useRef(false);

    // Calculate total duration and segments
    const { totalDuration, segments } = useMemo(() => {
        const total = slides.reduce((acc, s) => acc + (s.duration || 5), 0);
        let accumulated = 0;

        const segs = slides.map((slide, index) => {
            const start = accumulated;
            const widthPercent = ((slide.duration || 5) / total) * 100;
            accumulated += (slide.duration || 5);
            return {
                index,
                title: slide.title,
                badge: slide.badge,
                widthPercent,
                startPercent: (start / total) * 100
            };
        });

        return { totalDuration: total, segments: segs };
    }, [slides]);

    // Calculate Global Playhead Position
    const currentSegment = segments[currentSlideIndex];
    const globalProgress = currentSegment 
        ? currentSegment.startPercent + (currentSegment.widthPercent * (currentSlideProgress / 100))
        : 0;

    const calculateProgress = (clientX: number) => {
        if (!containerRef.current) return 0;
        const rect = containerRef.current.getBoundingClientRect();
        const x = clientX - rect.left;
        return Math.max(0, Math.min(100, (x / rect.width) * 100));
    };

    const handleMouseDown = (e: React.MouseEvent) => {
        isDragging.current = true;
        if (onSeekStart) onSeekStart();
        onSeek(calculateProgress(e.clientX));

        const handleMouseMove = (ev: MouseEvent) => {
            if (isDragging.current) {
                onSeek(calculateProgress(ev.clientX));
            }
        };

        const handleMouseUp = () => {
            isDragging.current = false;
            if (onSeekEnd) onSeekEnd();
            document.removeEventListener('mousemove', handleMouseMove);
            document.removeEventListener('mouseup', handleMouseUp);
        };

        document.addEventListener('mousemove', handleMouseMove);
        document.addEventListener('mouseup', handleMouseUp);
    };

    return (
        <div className="w-full px-6 pb-6 pt-2 select-none group">
            {/* Header / Time Display */}
            <div className="flex justify-between items-center mb-2 text-[10px] text-gray-500 font-mono uppercase tracking-widest">
                <span>Global Timeline</span>
                <span>{((globalProgress / 100) * totalDuration).toFixed(1)}s / {totalDuration.toFixed(1)}s</span>
            </div>

            {/* Timeline Track */}
            <div 
                ref={containerRef}
                className="h-10 w-full bg-[#111] rounded-md relative cursor-pointer overflow-hidden border border-white/5 hover:border-white/10 transition-colors"
                onMouseDown={handleMouseDown}
            >
                {/* Segments */}
                <div className="absolute inset-0 flex">
                    {segments.map((seg, i) => (
                        <div 
                            key={i}
                            style={{ width: `${seg.widthPercent}%` }}
                            className={`h-full border-r border-[#000] relative group/segment ${i === currentSlideIndex ? 'bg-white/5' : 'bg-transparent'}`}
                        >
                            {/* Segment Label (Badge) */}
                            <div className={`absolute top-2 left-2 text-[9px] font-bold truncate max-w-full px-1 py-0.5 rounded ${i === currentSlideIndex ? 'text-white bg-indigo-500/20' : 'text-gray-600'}`}>
                                {seg.badge}
                            </div>

                            {/* Hover tooltip logic could go here */}
                            <div className="absolute bottom-0 left-0 w-full h-0.5 bg-white/10 group-hover/segment:bg-white/20 transition-colors"></div>
                        </div>
                    ))}
                </div>

                {/* Global Playhead & Fill */}
                <div 
                    className="absolute top-0 bottom-0 left-0 bg-indigo-500/10 pointer-events-none border-r-2 border-indigo-500 transition-all duration-75 ease-linear z-10"
                    style={{ width: `${globalProgress}%` }}
                >
                    {/* Glowing head */}
                    <div className="absolute right-[-5px] top-1/2 -translate-y-1/2 w-2.5 h-6 bg-indigo-500 rounded-full shadow-[0_0_10px_rgba(99,102,241,0.5)] opacity-0 group-hover:opacity-100 transition-opacity"></div>
                </div>

            </div>
        </div>
    );
};

