  // We strictly hide content on the very first frame (progress ~ 0) if an intro transition is active.
  // We strictly hide content on the very last frame (progress ~ 100) if an outro transition is active.
  const shouldForceHide = (transitionType: string, isIntro: boolean) => {
      if (!animate) return false;
      if (transitionType === 'none') return false;

      // Use a small epsilon. For a 5s slide at 60fps, 1 frame is ~0.33%. 
      // 0.1 covers the absolute start/reset state.
      // 99.9 covers the absolute end.
      if (isIntro && progress <= 0.1) return true;
      if (!isIntro && progress >= 99.9) return true;

