        manualSave, applyTheme, applyTypography, randomizeLook,
        startNewProject, importProjectFile, downloadProjectFile, 
        loadRemoteProject, renameProject, toggleArchiveStatus, duplicateProject, fetchProjects
    } = usePresentation();

    // 2. Playback Logic
    const isGlobalSeeking = useRef(false);
    const autoTransitionRef = useRef(false);

    const handleSlideComplete = useCallback(() => {
        if (currentSlideIndex < slides.length - 1) {
            // Move to next slide
            autoTransitionRef.current = true;
            setCurrentSlideIndex(prev => prev + 1);
        } else {
            // End of presentation
            autoTransitionRef.current = false;
        }
    }, [currentSlideIndex, slides.length, setCurrentSlideIndex]);

    const { 
        isPlaying, 
        setIsPlaying,
        progress, 
        setProgress,
        togglePlay, 
        scrub, 
        reset 
    } = usePlayback(currentSlide?.duration, handleSlideComplete);


    // RESET / TRANSITION LOGIC:
    useEffect(() => {
        if (isGlobalSeeking.current) return;

        if (autoTransitionRef.current) {
            // This is an automatic transition to next slide
            setProgress(0);
            setIsPlaying(true);
            autoTransitionRef.current = false;
        } else {
            // This is a manual slide change (user clicked something)
            // Unless it's the very first load
            if (isLoaded) {
                 reset();
            }
        }
    }, [currentSlide?.id, isLoaded]); // Depend on ID change


    // 3. Render Helpers
    const containerRef = useRef<HTMLDivElement>(null);
    const scale = useScale(containerRef);

    // 4. Export Management
    const hiddenExportRef = useRef<HTMLDivElement>(null);
    const exportManager = useExportManager(slides, currentSlide, hiddenExportRef);

    // 5. Welcome Screen State
    const [showWelcomeScreen, setShowWelcomeScreen] = useState(true);

    // Automatically hide welcome screen when a project loads successfully
    useEffect(() => {
        if (slides.length > 0 && isLoaded) {
            // Project loaded
        }
    }, [slides, isLoaded]);

    const handleNewProject = () => {
        startNewProject();
        setShowWelcomeScreen(false);
    };

    const handleLoadProject = (id: string | number) => {
        loadRemoteProject(id);
        setShowWelcomeScreen(false);
    };

    const handleImportProject = (file: File) => {
        importProjectFile(file);
        setShowWelcomeScreen(false);
    };

    // --- Global Timeline Logic ---
    const handleGlobalSeek = (globalPercent: number) => {
        if (slides.length === 0) return;

        const totalDuration = slides.reduce((acc, s) => acc + (s.duration || 5), 0);
        const targetTime = (globalPercent / 100) * totalDuration;

        let accumulatedTime = 0;
        let targetIndex = 0;
        let localTime = 0;

        // Find which slide corresponds to the target time
        for (let i = 0; i < slides.length; i++) {
            const d = slides[i].duration || 5;
            if (accumulatedTime + d >= targetTime) {
                targetIndex = i;
                localTime = targetTime - accumulatedTime;
                break;
            }
            accumulatedTime += d;
        }

        // Clamp just in case
        if (targetIndex >= slides.length) {
             targetIndex = slides.length - 1;
             localTime = slides[targetIndex].duration || 5;
        }

        const localDuration = slides[targetIndex].duration || 5;
        const localProgress = (localTime / localDuration) * 100;

        // Apply changes
        setCurrentSlideIndex(targetIndex);
        scrub(localProgress);
    };

    // --- Global Pulse Loop ---
    // This updates a CSS variable for "Title Pulsating" so it remains continuous across slides.
    useEffect(() => {
        let rafId: number;
        const animatePulse = () => {
            const time = performance.now();
            // 4 second period sine wave (1.0 to 1.03)
            // Cycle: 0 -> 1 over 4000ms
            const t = (time % 4000) / 4000;
            // Cos wave: 1 at 0, 0 at 0.25, -1 at 0.5, 0 at 0.75, 1 at 1.0
            // We want 1 -> 1.03 -> 1
            // Use 0.5 - 0.5*cos(2*PI*t) -> 0 to 1 to 0
            const factor = 0.5 - 0.5 * Math.cos(2 * Math.PI * t);
            const scale = 1.0 + (0.03 * factor); // Range 1.00 to 1.03

            // Set global variable on root
            document.documentElement.style.setProperty('--global-pulse-scale', scale.toFixed(5));

            rafId = requestAnimationFrame(animatePulse);
        };

        rafId = requestAnimationFrame(animatePulse);
        return () => cancelAnimationFrame(rafId);
    }, []);

    // If still loading initial state
    if (!isLoaded && !currentSlide && !showWelcomeScreen) return <LoadingScreen />;

    return (
        <div className="flex h-screen w-screen bg-[#050505] text-white flex-col relative">

            <WelcomeScreen 
                isOpen={showWelcomeScreen}
                onClose={() => setShowWelcomeScreen(false)}
                recentProjects={savedProjects}
                isLoadingProjects={isLoadingProjects}
                onNewProject={handleNewProject}
                onLoadProject={handleLoadProject}
                onImportProject={handleImportProject}
                onRenameProject={renameProject}
                onToggleArchive={toggleArchiveStatus}
                onDuplicateProject={duplicateProject}
            />

            {/* Hidden Renderer for Export Operations */}
            <HiddenExportRenderer 
                ref={hiddenExportRef} 
                slide={exportManager.exportingSlide || currentSlide} 
                progress={exportManager.exportRenderProgress} 
            />

            {/* Top Navigation Bar */}
            <TopBar 
                currentSlide={currentSlide}
                currentProjectName={currentProjectName}
                saveStatus={saveStatus}
                isExporting={exportManager.isExporting}
                onApplyTheme={applyTheme}
                onApplyTypography={applyTypography}
                onRandomize={randomizeLook}
                onManualSave={manualSave}
                onNewProject={handleNewProject}
                onLoadProject={handleImportProject}
                onSaveProject={downloadProjectFile}
                onOpenExport={exportManager.openExportModal}
                onOpenWelcome={() => { fetchProjects(); setShowWelcomeScreen(true); }}
            />

            {/* Main Workspace */}
            <div className="flex-1 flex overflow-hidden">
                {/* Left: Preview Area */}
                <div className="flex-1 flex flex-col relative bg-[#050505] overflow-hidden">

                    {/* Slide Viewport */}
                    <div className="flex-1 relative flex items-center justify-center overflow-hidden" ref={containerRef}>
                        <div className="relative shadow-2xl shadow-black">
                            <SlideRenderer 
                                key={`${currentSlide?.id}-${currentSlide?.textTransition}`} 
                                data={currentSlide || slides[0]} 
                                scale={scale}
                                progress={progress}
                            />
                        </div>

                        {/* Floating Local Controls */}
                        <PreviewControls 
                            currentSlideIndex={currentSlideIndex + 1} 
                            totalSlides={slides.length} 
                            onNext={() => {
                                if (currentSlideIndex < slides.length - 1) {
                                    setCurrentSlideIndex(currentSlideIndex + 1);
                                    // Manual change, useEffect will reset
                                }
                            }} 
                            onPrev={() => {
                                if (currentSlideIndex > 0) {
                                    setCurrentSlideIndex(currentSlideIndex - 1);
                                }
                            }} 
                            isPlaying={isPlaying}
                            onTogglePlay={togglePlay}
                            progress={progress}
                            onScrub={scrub}
                        />
                    </div>

                    {/* Bottom: Global Timeline Strip */}
                    <div className="shrink-0 bg-[#0a0a0a] border-t border-white/5 z-40 relative">
                        <GlobalTimeline 
                            slides={slides}
                            currentSlideIndex={currentSlideIndex}
                            currentSlideProgress={progress}
                            isPlaying={isPlaying}
                            onTogglePlay={togglePlay}
                            onSeekStart={() => { isGlobalSeeking.current = true; }}
                            onSeekEnd={() => { isGlobalSeeking.current = false; }}
                            onSeek={handleGlobalSeek}
                        />
                    </div>
                </div>

                {/* Right: Editor Sidebar */}
                <EditorSidebar 
                    slides={slides}
                    currentSlideIndex={currentSlideIndex}
                    onUpdateSlide={updateSlide}
                    onAddSlide={addSlide}
                    onDuplicateSlide={duplicateSlide}
                    onDeleteSlide={deleteSlide}
                    onSelectSlide={setCurrentSlideIndex}
                    onReorderSlides={reorderSlide}
                />
            </div>

            {/* Export Modal */}
            <ExportModal 
                isOpen={exportManager.isExportModalOpen}
                onClose={() => exportManager.setIsExportModalOpen(false)}
                tab={exportManager.exportModalTab}
                setTab={exportManager.setExportModalTab}
                scope={exportManager.exportScope}
                slideCount={slides.length}
                currentSlideBadge={currentSlide?.badge || ""}
                quality={exportManager.exportQuality}
                setQuality={exportManager.setExportQuality}
                bitrate={exportManager.exportBitrate}
                setBitrate={exportManager.setExportBitrate}
                fps={exportManager.exportFps}
                setFps={exportManager.setExportFps}
                format={exportManager.exportFormat}
                setFormat={exportManager.setExportFormat}
                imageFormat={exportManager.exportImageFormat}
                setImageFormat={exportManager.setExportImageFormat}
                isExporting={exportManager.isExporting}
                progress={exportManager.exportProgressStatus}
                queue={exportManager.exportQueue}
                onQueue={exportManager.queueExport}
                onStart={() => exportManager.executeExport()}
                onProcessQueue={exportManager.processQueue}
                onDeleteJob={exportManager.deleteJob}
            />

        </div>
    );
};

export default App;

import React, { useState, useRef } from 'react';
import { SlideData, ExportJob } from '../types';
import * as Mp4Muxer from 'mp4-muxer';
import { toCanvas } from 'html-to-image';
import JSZip from 'jszip';

export const useExportManager = (
    slides: SlideData[], 
    currentSlide: SlideData,
    exportContainerRef: React.RefObject<HTMLDivElement | null>
) => {
    // UI State
    const [isExportModalOpen, setIsExportModalOpen] = useState(false);
    const [exportModalTab, setExportModalTab] = useState<'settings' | 'queue'>('settings');

    // Settings State (Local to manager)
    const [exportScope, setExportScope] = useState<'current' | 'all'>('current');
    const [exportQuality, setExportQuality] = useState<'720p' | '1080p' | '4k'>('1080p');
    const [exportBitrate, setExportBitrate] = useState<'low' | 'medium' | 'high'>('medium');
    const [exportFps, setExportFps] = useState<30 | 60>(60);
    const [exportFormat, setExportFormat] = useState<'mp4' | 'zip' | 'folder'>('mp4');
    const [exportImageFormat, setExportImageFormat] = useState<'jpeg' | 'png'>('jpeg');

    // Execution State
    const [exportQueue, setExportQueue] = useState<ExportJob[]>([]);
    const [isExporting, setIsExporting] = useState(false);
    const [exportProgressStatus, setExportProgressStatus] = useState(0);
    const [exportingSlide, setExportingSlide] = useState<SlideData | null>(null);
    const [exportRenderProgress, setExportRenderProgress] = useState(0);

    const openExportModal = (scope: 'current' | 'all') => {
        setExportScope(scope);
        setIsExportModalOpen(true);
        setExportModalTab('settings');
    };

    const queueExport = () => {
        const slidesSnapshot = exportScope === 'current' ? [currentSlide] : [...slides];
        const newJob: ExportJob = {
            id: Date.now().toString(),
            status: 'pending',
            createdAt: Date.now(),
            scope: exportScope,
            slides: JSON.parse(JSON.stringify(slidesSnapshot)),
            quality: exportQuality,
            bitrate: exportBitrate,
            fps: exportFps,
            format: exportFormat,
            imageFormat: exportImageFormat
        };
        setExportQueue([...exportQueue, newJob]);
        setExportModalTab('queue');
    };

    const processQueue = async () => {
        if (isExporting) return;
        const pending = exportQueue.filter(j => j.status === 'pending');
        if (pending.length === 0) return;

        for (const job of pending) {
            setExportQueue(prev => prev.map(j => j.id === job.id ? { ...j, status: 'processing' } : j));
            try {
                await executeExport(job);
                setExportQueue(prev => prev.map(j => j.id === job.id ? { ...j, status: 'completed' } : j));
            } catch (e) {
                console.error(e);
                setExportQueue(prev => prev.map(j => j.id === job.id ? { ...j, status: 'failed' } : j));
            }
            await new Promise(r => setTimeout(r, 1000));
        }
        setIsExporting(false);
        setExportingSlide(null);
        setExportProgressStatus(0);
    };

    const executeExport = async (job?: ExportJob) => {
        if (!job && isExporting) return;
        if (!exportContainerRef.current) return;

        setIsExporting(true);
        setExportProgressStatus(0);

        const cfgQuality = job ? job.quality : exportQuality;
        const cfgBitrate = job ? job.bitrate : exportBitrate;
        const cfgFps = job ? job.fps : exportFps;
        const cfgFormat = job ? job.format : exportFormat;
        const cfgScope = job ? job.scope : exportScope;
        const cfgSlides = job ? job.slides : (exportScope === 'current' ? [currentSlide] : slides);
        const cfgImageFormat = job ? job.imageFormat : exportImageFormat;

        const FPS = cfgFps;
        let WIDTH = 1920;
        let HEIGHT = 1080;
        let bitRate = 5_000_000;

        let baseBitrate = 0;
        if (cfgQuality === '720p') {
            WIDTH = 1280; HEIGHT = 720;
            baseBitrate = cfgBitrate === 'low' ? 1.5e6 : cfgBitrate === 'medium' ? 2.5e6 : 4e6;
        } else if (cfgQuality === '1080p') {
            WIDTH = 1920; HEIGHT = 1080;
            baseBitrate = cfgBitrate === 'low' ? 3e6 : cfgBitrate === 'medium' ? 5e6 : 8e6;
        } else if (cfgQuality === '4k') {
            WIDTH = 3840; HEIGHT = 2160;
            baseBitrate = cfgBitrate === 'low' ? 8e6 : cfgBitrate === 'medium' ? 12e6 : 20e6;
        }

        // Increase bitrate slightly for higher frame rates to maintain per-frame quality
        if (FPS === 60) baseBitrate *= 1.5;
        bitRate = baseBitrate;

        let muxer: any = null;
        let videoEncoder: VideoEncoder | null = null;
        let zip: JSZip | null = null;

        try {
            // Generate a safe folder name for this export
            const baseName = cfgScope === 'current' && cfgSlides.length === 1 ? `slide-${cfgSlides[0].badge.replace(/\s+/g,'_')}` : `presentation`;
            const timestamp = Date.now();
            const folderName = `${baseName}_${timestamp}`;

            if (cfgFormat === 'mp4') {
                muxer = new Mp4Muxer.Muxer({
                    target: new Mp4Muxer.ArrayBufferTarget(),
                    video: { codec: 'avc', width: WIDTH, height: HEIGHT },
                    fastStart: 'in-memory',
                    firstTimestampBehavior: 'offset',
                });
                const codecStr = cfgQuality === '4k' ? 'avc1.640033' : 'avc1.4d002a';

                videoEncoder = new VideoEncoder({
                    output: (chunk, meta) => {
                        try {
                            muxer.addVideoChunk(chunk, meta);
                        } catch (err) {
                            console.error("Muxer error:", err);
                        }
                    },
                    error: (e) => {
                        console.error("VideoEncoder error:", e);
                        alert(`Video Encoding Error: ${e.message}`);
                    }
                });

                videoEncoder.configure({ codec: codecStr, width: WIDTH, height: HEIGHT, bitrate: bitRate });
            } else if (cfgFormat === 'zip') {
                zip = new JSZip();
            }

            let totalExportFrames = 0;
            cfgSlides.forEach(s => totalExportFrames += Math.ceil((s.duration || 5) * FPS));

            // Start at 1 for user-friendly file numbering (frame_00001)
            let globalFrameCount = 1;

            for (const slide of cfgSlides) {
                setExportingSlide(slide);
                // Wait for React to render the new slide in the hidden container
                await new Promise(r => setTimeout(r, 250));

                const duration = slide.duration || 5;
                const frames = Math.ceil(duration * FPS);

                for (let i = 0; i < frames; i++) {
                    const prog = (i / (frames - 1)) * 100;
                    setExportRenderProgress(prog);

                    // Use (globalFrameCount - 1) for progress calculation to start at 0%
                    setExportProgressStatus(Math.round(((globalFrameCount - 1) / totalExportFrames) * 100));

                    // Allow UI updates, but keep it fast (0ms)
                    await new Promise(r => setTimeout(r, 0));

                    if (exportContainerRef.current) {
                        try {
                            // --- MANUAL PULSE SYNC FOR EXPORT ---
                            // We must calculate what the scale would be at this specific timestamp
                            // to ensure the export has continuous pulsing like the live preview.
                            // 4s period = 4000ms.
                            const frameTimeMs = ((globalFrameCount - 1) * 1000) / FPS;
                            const t = (frameTimeMs % 4000) / 4000;
                            const factor = 0.5 - 0.5 * Math.cos(2 * Math.PI * t);
                            const scale = 1.0 + (0.03 * factor); // Range 1.00 to 1.03

                            exportContainerRef.current.style.setProperty('--global-pulse-scale', scale.toFixed(5));
                            // -------------------------------------

                            const canvas = await toCanvas(exportContainerRef.current, {
                                width: WIDTH, height: HEIGHT, pixelRatio: 1, cacheBust: true,
                                style: { transform: 'none', transformOrigin: 'top left' },
                                fontEmbedCSS: '',
                            });

                            if (cfgFormat === 'mp4' && videoEncoder) {
                                // Ensure timestamp starts at 0 for the video stream
                                // (globalFrameCount - 1) ensures the first frame is at timestamp 0
                                const timestamp = ((globalFrameCount - 1) * 1e6) / FPS;
                                const duration = 1e6 / FPS;

                                const frame = new VideoFrame(canvas, { timestamp, duration });

                                // FIX: Insert Keyframe every 2 seconds to ensure seekability
                                // FPS * 2 means one keyframe every 2 seconds.
                                const keyFrameInterval = FPS * 2;
                                const shouldBeKeyFrame = (globalFrameCount - 1) % keyFrameInterval === 0;

                                videoEncoder.encode(frame, { keyFrame: shouldBeKeyFrame });
                                frame.close();
                            } else if (cfgFormat === 'zip' && zip) {
                                const mime = cfgImageFormat === 'jpeg' ? 'image/jpeg' : 'image/png';
                                const q = cfgImageFormat === 'jpeg' ? 0.9 : undefined;
                                const ext = cfgImageFormat === 'jpeg' ? 'jpg' : 'png';
                                const blob = await new Promise<Blob | null>(r => canvas.toBlob(r, mime, q));

                                // File naming uses 1-based index: frame_00001
                                if (blob) zip.file(`frame_${String(globalFrameCount).padStart(5,'0')}.${ext}`, blob);
                            } else if (cfgFormat === 'folder') {
                                // DIRECT FOLDER OUTPUT VIA EXTENSION
                                const mime = cfgImageFormat === 'jpeg' ? 'image/jpeg' : 'image/png';
                                const q = cfgImageFormat === 'jpeg' ? 0.9 : undefined;
                                const ext = cfgImageFormat === 'jpeg' ? 'jpg' : 'png';

                                const blob = await new Promise<Blob | null>(r => canvas.toBlob(r, mime, q));
                                if (blob) {
                                    const url = URL.createObjectURL(blob);
                                    // Send to extension
                                    window.postMessage({
                                        type: 'SLIDEFORGE_DOWNLOAD',
                                        payload: {
                                            url: url,
                                            // File naming uses 1-based index: frame_00001
                                            filename: `${folderName}/frame_${String(globalFrameCount).padStart(5,'0')}.${ext}`
                                        }
                                    }, '*');

                                    // Clean up object URL after a delay to ensure extension read it
                                    setTimeout(() => URL.revokeObjectURL(url), 5000);

                                    // Slight delay to prevent flooding
                                    await new Promise(r => setTimeout(r, 50));
                                }
                            }
                        } catch (err) { console.warn("Frame capture error:", err); }
                    }
                    globalFrameCount++;
                }
            }

            // Finalization phase
            if (cfgFormat === 'mp4' && videoEncoder && muxer) {
                // Important: flush must complete before finalizing muxer
                await videoEncoder.flush();
                videoEncoder.close();
                videoEncoder = null; // Prevent double cleanup

                muxer.finalize();
                const blob = new Blob([muxer.target.buffer], { type: 'video/mp4' });
                const filename = `${baseName}_${cfgQuality}_${cfgFps}fps.mp4`;
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url; a.download = filename;
                document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
            } else if (cfgFormat === 'zip' && zip) {
                const blob = await zip.generateAsync({ type: "blob" });
                const filename = `${baseName}_frames.zip`;
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url; a.download = filename;
                document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
            } else if (cfgFormat === 'folder') {
                await new Promise(r => setTimeout(r, 500));
            }

            if (!job) {
                setTimeout(() => { setIsExportModalOpen(false); setIsExporting(false); setExportProgressStatus(0); }, 1000);
            }
        } catch (e: any) {
            console.error("Export Failed", e);
            if (!job) alert(`Export failed: ${e.message}`);
            else throw e;
        } finally {
            if (videoEncoder && videoEncoder.state !== 'closed') {
                try { videoEncoder.close(); } catch(e) { console.warn("Could not close encoder:", e); }
            }
            if (!job) { setExportingSlide(null); setIsExporting(false); }
        }
    };

    return {
        // UI State
        isExportModalOpen, setIsExportModalOpen,
        exportModalTab, setExportModalTab,
        // Settings State setters
        setExportQuality, setExportBitrate, setExportFps, setExportFormat, setExportImageFormat,
        // Settings State getters
        exportScope, exportQuality, exportBitrate, exportFps, exportFormat, exportImageFormat,
        // Queue & Status
        exportQueue, setExportQueue,
        isExporting,
        exportProgressStatus,
        exportingSlide,
        exportRenderProgress,
        // Actions
        openExportModal,
        queueExport,
        processQueue,
        executeExport, // Direct start
        deleteJob: (id: string) => setExportQueue(q => q.filter(j => j.id !== id))
    };
};

import React from 'react';
import { SlideData } from '../types';

interface SlideRendererProps {
  data: SlideData;
  scale?: number;
  animate?: boolean;
  progress?: number; // 0 to 100
}

const SlideRenderer: React.FC<SlideRendererProps> = ({ 
    data, 
    scale = 1, 
    animate = true, 
    progress = 0 
}) => {
  const { 
    theme, 
    typography = 'modern-sans', // Default fallback
    badge, 
    title, 
    description, 
    imageUrl, 
    textTransition = 'slide-up', 
    imageTransition = 'zoom-in',
    textOutroTransition = 'none',
    imageOutroTransition = 'none',

    // Default to 1s if undefined for backward compatibility
    textTransitionDuration = 1,
    imageTransitionDuration = 1,
    textOutroDuration = 1,
    imageOutroDuration = 1,

    layout = 'text-image' // Default fallback
  } = data;

  // Base Slide Dimensions (16:9 Aspect Ratio based on 1920x1080)
  const width = 1920;
  const height = 1080;

  // Common wrapper style
  const wrapperStyle: React.CSSProperties = {
    width: `${width}px`,
    height: `${height}px`,
    transform: `scale(${scale})`,
    transformOrigin: 'center center',
    overflow: 'hidden',
    position: 'relative',
    display: 'flex',
    boxShadow: '0 0 50px rgba(0,0,0,0.5)',
  };

  // --- Animation Logic ---
  const durationSeconds = data.duration || 5;
  const currentSeconds = durationSeconds * (progress / 100);

  const getControlledAnimationStyle = (baseDelayMs: number, type: 'intro' | 'outro' = 'intro', durationVal: number = 1): React.CSSProperties => {
    if (!animate) return {};

    const elapsedSeconds = currentSeconds;

    let calculatedDelayStr = '';

    if (type === 'intro') {
        calculatedDelayStr = `calc(${baseDelayMs}ms - ${elapsedSeconds}s)`;
    } else {
        const outroStartMs = (durationSeconds * 1000) - (durationVal * 1000);
        calculatedDelayStr = `calc(${outroStartMs}ms - ${elapsedSeconds}s)`;
    }

    return {
      animationPlayState: 'paused',
      animationDelay: calculatedDelayStr,
      animationFillMode: 'both',
      animationIterationCount: 1,
      animationDuration: `${durationVal}s` // Override CSS default
    };
  };

  const getAnimationClass = (transition: string, type: 'intro' | 'outro') => {
    if (!animate || transition === 'none') return '';
    return `anim-${transition}${type === 'outro' ? '-out' : ''}`;
  };

  const textIntroClass = getAnimationClass(textTransition, 'intro');
  const textOutroClass = getAnimationClass(textOutroTransition, 'outro');
  const imgIntroClass = getAnimationClass(imageTransition, 'intro');
  const imgOutroClass = getAnimationClass(imageOutroTransition, 'outro');

  // FOUC Prevention & Clean Cut Logic
  const isFirstFrame = animate && progress <= 0.0001;
  const isLastFrame = animate && progress >= 99.9999;

  // Only hide start frame if there is an active transition (not 'none')
  const hideTextStart = isFirstFrame && textTransition !== 'none';
  const hideImgStart = isFirstFrame && imageTransition !== 'none';

  // Only hide end frame if there is an active transition (not 'none')
  const hideTextEnd = isLastFrame && textOutroTransition !== 'none';
  const hideImgEnd = isLastFrame && imageOutroTransition !== 'none';

  const textIntroStyle: React.CSSProperties = {
      ...getControlledAnimationStyle(0, 'intro', textTransitionDuration),
      ...(hideTextStart ? { visibility: 'hidden' } : {})
  };
  const textOutroStyle: React.CSSProperties = {
      ...getControlledAnimationStyle(0, 'outro', textOutroDuration),
      ...(hideTextEnd ? { visibility: 'hidden' } : {})
  };

  const imgIntroStyle: React.CSSProperties = {
      ...getControlledAnimationStyle(0, 'intro', imageTransitionDuration),
      ...(hideImgStart ? { visibility: 'hidden' } : {})
  };
  const imgOutroStyle: React.CSSProperties = {
      ...getControlledAnimationStyle(0, 'outro', imageOutroDuration),
      ...(hideImgEnd ? { visibility: 'hidden' } : {})
  };

  // --- Title Pulse Logic (Global Continuous) ---
  // If not animating (thumbnail), force scale to 1. 
  // If animating, leave transform empty so CSS variable takes over.
  const pulseWrapperStyle: React.CSSProperties = !animate ? { transform: 'scale(1)' } : {};

  // --- Ripple Effect Logic ---
  const getRippleStyle = (offsetSeconds: number): React.CSSProperties => {
      if (!animate) return {}; 

      return {
          animationPlayState: 'paused',
          animationDelay: `calc(${offsetSeconds}s - ${currentSeconds}s)`,
      };
  };

  const titleStyle: React.CSSProperties = {
    fontSize: 'var(--slide-title-size)',
  };

  // Layout Logic
  const isTextOnly = layout === 'text-only';

  // Wrapper classes for layout
  const containerClasses = isTextOnly 
    ? `theme-${theme} typography-${typography} flex-col items-center justify-center p-[100px] text-center`
    : `theme-${theme} typography-${typography} flex-row items-center p-[70px] gap-20`;

  // Text container classes
  const textContainerClasses = isTextOnly
    ? `w-full z-10 flex flex-col justify-center items-center text-center anim-outro-wrapper ${textOutroClass}`
    : `flex-1 z-10 flex flex-col justify-center items-start text-left anim-outro-wrapper ${textOutroClass}`;

  // Badge alignment for text-only
  const badgeClasses = isTextOnly 
    ? "badge inline-block px-10 py-4 rounded-full font-bold uppercase mb-10 tracking-wider w-fit mx-auto whitespace-nowrap"
    : "badge inline-block px-10 py-4 rounded-full font-bold uppercase mb-10 tracking-wider w-fit whitespace-nowrap";

  const descClasses = isTextOnly
    ? "slide-description leading-relaxed opacity-85 max-w-[80%] mx-auto whitespace-pre-wrap"
    : "slide-description leading-relaxed opacity-85 max-w-[90%] whitespace-pre-wrap";

  return (
    <div 
        style={wrapperStyle} 
        className={containerClasses}
    >
        {/* GENERIC SLIDE DECORATIONS */}
        <div className="theme-deco-slide-1"></div>
        <div className="theme-deco-slide-2"></div>

        <>
            {/* Text Section */}
            <div className={textContainerClasses} style={textOutroStyle}>
                <div className={`anim-content w-full ${textIntroClass}`} style={textIntroStyle}>
                    <span className={badgeClasses} style={{ fontSize: 'var(--slide-badge-size)' }}>
                        {badge}
                    </span>

                    {/* Wrapped Title for Smooth Scaling */}
                    <div className="pulsate-wrapper mb-10 max-w-full" style={pulseWrapperStyle}>
                        <h1 className="slide-title font-bold leading-[1.1] whitespace-pre-wrap" style={titleStyle}>
                            {title}
                        </h1>
                    </div>

                    <p className={descClasses} style={{ fontSize: 'var(--slide-desc-size)' }}>
                        {description}
                    </p>
                </div>
            </div>

            {/* Image Section - Only render if not text-only */}
            {!isTextOnly && (
                <div className={`flex-1 flex justify-center items-center relative z-10 h-full anim-outro-wrapper ${imgOutroClass}`} style={imgOutroStyle}>
                    <div className={`w-full h-full flex items-center justify-center anim-content ${imgIntroClass}`} style={imgIntroStyle}>
                        {/* Visual Wrapper for Effects */}
                        <div className="slide-visual-wrapper relative flex justify-center items-center">
                              <img 
                                  src={imageUrl} 
                                  alt="Slide Visual"
                                  crossOrigin="anonymous" 
                                  className="slide-image relative z-10 block"
                                  style={{ 
                                      maxHeight: 'var(--slide-img-max-height)', 
                                      maxWidth: '100%',
                                      objectFit: 'contain',
                                      margin: 0,
                                      padding: 0,
                                      border: 'none',
                                      outline: 'none',
                                      transform: 'none',
                                      boxShadow: 'inherit' // Allow themes to set box-shadow on image
                                  }}
                              />
                              {/* Dynamic Effect Layers - Controlled */}
                              <div className="slide-image-effect effect-1 absolute inset-0 z-0 pointer-events-none" style={getRippleStyle(0)}></div>
                              <div className="slide-image-effect effect-2 absolute inset-0 z-0 pointer-events-none" style={getRippleStyle(1)}></div>
                              <div className="slide-image-effect effect-3 absolute inset-0 z-0 pointer-events-none" style={getRippleStyle(2)}></div>
                        </div>
                    </div>
                </div>
            )}
        </>
      </div>
  );
};

export default SlideRenderer;
